import pysam

def filter_bam(input_bam, output_bam, min_mapq=30):
    # Open input BAM
    with pysam.AlignmentFile(input_bam, "rb") as infile:
        # Create output BAM with same header, sorted by coordinate
        with pysam.AlignmentFile(output_bam, "wb", header=infile.header, sort='coordinate') as outfile:
            for read in infile:
                if read.mapping_quality >= min_mapq:
                    outfile.write(read)
    # Index the output BAM
    pysam.index(output_bam)

if __name__ == "__main__":
    filter_bam("input.bam", "output.bam", 30)
